(function($) {
  "use strict";

  const PLUGIN_NAME = 'scrolly';
  const EVENT_KEY = `click.${PLUGIN_NAME}`;

 
  const calculateScrollPos = ($target, settings) => {
    if (!$target.length) return null;

    let offset = $target.offset().top;

    if (settings.anchor === 'middle') {
      const windowHeight = $(window).height();
      const targetHeight = $target.outerHeight();
      offset -= (windowHeight - targetHeight) / 2;
    }

    const extraOffset = typeof settings.offset === 'function' 
      ? settings.offset() 
      : settings.offset;

    return offset - extraOffset;
  };

  $.fn.scrolly = function(options) {
    const $elements = $(this);

    if ($elements.length === 0) return $elements;

    if ($elements.length > 1) {
      $elements.each(function() {
        $(this).scrolly(options);
      });
      return $elements;
    }

    const settings = $.extend({
      anchor: 'top',
      easing: 'swing',
      offset: 0,
      parent: $('body, html'),
      pollOnce: false,
      speed: 1000
    }, options);

    const href = $elements.attr('href');

    if (!href || href.charAt(0) !== '#' || href.length < 2) {
      return $elements;
    }

    const $target = $(href);
    let cachedPos = settings.pollOnce ? calculateScrollPos($target, settings) : null;

    $elements.off(EVENT_KEY).on(EVENT_KEY, function(e) {
      const targetPos = (cachedPos !== null) ? cachedPos : calculateScrollPos($target, settings);

      if (targetPos !== null) {
        e.preventDefault();
        settings.parent
          .stop()
          .animate({ scrollTop: targetPos }, settings.speed, settings.easing);
      }
    });

    return $elements;
  };

})(jQuery);


